sql:
SELECT COUNT(DISTINCT athlete_id) AS total_athletes
FROM athletes
WHERE sport_id = 1 AND birth_date BETWEEN '1990-01-01' AND '2000-12-31';

SELECT COUNT(athlete_id) AS male_count, AVG(height) AS average_height, AVG(weight) AS average_weight 
FROM athletes 
WHERE gender = 'Male';

SELECT country_code, COUNT(athlete_id) AS athlete_count
FROM athletes
GROUP BY country_code;

SELECT AVG(medal_value) AS average_medal_value
FROM results
WHERE medal = 'Gold' AND year = 1948;

SELECT name, birth_date
FROM athletes
ORDER BY birth_date ASC;

