FROM athletes
WHERE training_status = 'Active' AND injury_status = 'Healthy';

SELECT COUNT(athlete_id) AS athlete_count, country_code
FROM athletes
WHERE country_code = 'USA';

SELECT COUNT(*) 
FROM events_schedule 
WHERE date BETWEEN '2023-01-01' AND '2023-12-31';
